// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Login', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Login', async function() {
    await driver.get("http://localhost:4200//login");
    await driver.manage().window().setRect({ width: 1360, height: 768 });
    assert(await driver.findElement(By.css(".ant-typography")).getText() == "評価制度");
    assert(await driver.findElement(By.xpath("//span[contains(.,\'ログイン\')]")).getText() == "ログイン");
    {
      const attribute = await driver.findElement(By.xpath("//form[@id=\'login_form\']/div[3]/div/div/div/div/div/button")).getAttribute("style");
      vars["button_login_color"] = attribute;
    }
    assert(vars["button_login_color"].toString() == "background-color: rgb(0, 168, 95); height: 3rem;");
    {
      const attribute = await driver.findElement(By.xpath("//form[@id=\'login_form\']/div/div/div/div/div/div/span/input")).getAttribute("placeholder");
      vars["input_email_placeholder"] = attribute;
    }
    assert(vars["input_email_placeholder"].toString() == "ユーザ名");
    {
      const attribute = await driver.findElement(By.xpath("//form[@id=\'login_form\']/div[2]/div/div/div/div/div/span/input")).getAttribute("placeholder");
      vars["input_password_placeholder"] = attribute;
    }
    await driver.findElement(By.id("login_form_email")).click();
    await driver.findElement(By.id("login_form_email")).sendKeys("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa");
    assert(await driver.findElement(By.xpath("//div[@id=\'login_form_email_help\']/div")).getText() == "30文字以内で入力してください。");
    await driver.findElement(By.id("login_form_password")).click();
    await driver.findElement(By.id("login_form_password")).sendKeys("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa");
    assert(await driver.findElement(By.xpath("//div[@id=\'login_form_password_help\']/div")).getText() == "100文字以内で入力してください。");
    await driver.findElement(By.id("login_form_email")).click();
    await driver.findElement(By.id("login_form_email")).sendKeys(" ");
    await driver.findElement(By.id("login_form_password")).click();
    await driver.findElement(By.id("login_form_password")).sendKeys(" ");
    await driver.findElement(By.xpath("//form[@id=\'login_form\']/div[3]/div/div/div/div/div/button/span")).click();
    assert(await driver.findElement(By.css("#login_form_email_help > .ant-form-item-explain-error")).getText() == "この項目を入力してください。");
    assert(await driver.findElement(By.css("#login_form_password_help > .ant-form-item-explain-error")).getText() == "この項目を入力してください。");
    {
      const element = await driver.findElement(By.xpath("//form[@id=\'login_form\']/div[3]/div/div/div/div/div/button"));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }
    vars["backgroundColor"] = await driver.executeScript("return getComputedStyle(document.getElementsByClassName(\"ant-btn\")[0]).backgroundColor");
    assert(vars["backgroundColor"].toString() == "rgb(255, 255, 255)");
    await driver.findElement(By.id("login_form_email")).click();
    await driver.findElement(By.id("login_form_email")).sendKeys("wrong_account");
    await driver.findElement(By.id("login_form_password")).click();
    await driver.findElement(By.id("login_form_password")).sendKeys("wrongaccount");
    await driver.findElement(By.xpath("//button/span")).click();
    assert(await driver.findElement(By.xpath("//div/span[2]")).getText() == "ユーザ名またはパスワードが正しくありません。もう一度入力してください。");
    await driver.findElement(By.id("login_form_email")).click();
    await driver.findElement(By.id("login_form_email")).sendKeys("tran.le.ha.nam");
    await driver.findElement(By.id("login_form_password")).sendKeys("123456789");
    await driver.findElement(By.xpath("//button/span")).click();
    await driver.wait(until.elementLocated(By.xpath("//div[@id=\'root\']/section/section/main/div/h3")), 2000);
    await driver.findElement(By.xpath("//button/div")).click();
    await driver.findElement(By.xpath("//button[2]/span")).click();
  });
});
